<script setup lang="ts">
import { defineVaDataTableColumns } from 'vuestic-ui'
import { computed, PropType } from 'vue'
import { AffiliateMePromoCodeRow, AffiliateMePromoCodeSummary } from '../types'
import { Pagination } from '../composables/useAffiliateMe'

const columns = defineVaDataTableColumns([
    { label: '優惠碼', key: 'code' },
    { label: '使用次數', key: 'usageCount' },
    { label: '累積產生佣金', key: 'commissionTotal' },
])

const props = defineProps({
    rows: {
        type: Array as PropType<AffiliateMePromoCodeRow[]>,
        required: true,
    },
    summary: {
        type: Object as PropType<AffiliateMePromoCodeSummary>,
        required: true,
    },
    loading: { type: Boolean, default: false },
    pagination: { type: Object as PropType<Pagination>, required: true },
})

const emit = defineEmits<{
    (event: 'update:page', page: number): void
    (event: 'update:perPage', perPage: number): void
}>()

const totalPages = computed(() => Math.ceil(props.pagination.total / props.pagination.perPage))
</script>

<template>
    <VaDataTable :columns="columns" :items="rows" :loading="$props.loading">
        <template #cell(code)="{ rowData }">
            <span class="font-semibold text-primary">{{ rowData.code }}</span>
        </template>

        <template #cell(usageCount)="{ rowData }">
            {{ Number(rowData.usageCount).toLocaleString() }}
        </template>

        <template #cell(commissionTotal)="{ rowData }">
            VND {{ Number(rowData.commissionTotal).toLocaleString() }}
        </template>
    </VaDataTable>

    <div class="grid grid-cols-1 md:grid-cols-2 gap-2 my-4">
        <VaCard outlined>
            <VaCardContent class="flex items-center justify-between">
                <span class="text-secondary">使用次數合計</span>
                <span class="font-semibold">{{ summary.totalUsageCount.toLocaleString() }}</span>
            </VaCardContent>
        </VaCard>
        <VaCard outlined>
            <VaCardContent class="flex items-center justify-between">
                <span class="text-secondary">累積產生佣金合計</span>
                <span class="font-semibold text-success">VND {{ summary.totalCommissionAmount.toLocaleString() }}</span>
            </VaCardContent>
        </VaCard>
    </div>

    <div class="flex flex-col-reverse md:flex-row gap-2 justify-between items-center py-2">
        <div>
            <b>{{ $props.pagination.total }} results.</b>
            Results per page
            <VaSelect
                :model-value="$props.pagination.perPage"
                class="!w-20"
                :options="[10, 50, 100]"
                @update:modelValue="(value) => emit('update:perPage', Number(value))"
            />
        </div>

        <div v-if="totalPages > 1" class="flex">
            <VaButton
                preset="secondary"
                icon="va-arrow-left"
                aria-label="Previous page"
                :disabled="$props.pagination.page === 1"
                @click="emit('update:page', $props.pagination.page - 1)"
            />
            <VaButton
                class="mr-2"
                preset="secondary"
                icon="va-arrow-right"
                aria-label="Next page"
                :disabled="$props.pagination.page === totalPages"
                @click="emit('update:page', $props.pagination.page + 1)"
            />
            <VaPagination
                :model-value="$props.pagination.page"
                buttons-preset="secondary"
                :pages="totalPages"
                :visible-pages="5"
                :boundary-links="false"
                :direction-links="false"
                @update:modelValue="(value) => emit('update:page', Number(value))"
            />
        </div>
    </div>
</template>
